        assert_eq!(cell.accessor_count(), 2);
        assert_eq!(guard1.len(), 3);
        assert_eq!(guard2.len(), 3);
        drop(guard1);
        drop(guard2);
        assert_eq!(cell.accessor_count(), 0);
